package com.example.lottery.admin;

import androidx.test.ext.junit.rules.ActivityScenarioRule;
import androidx.test.ext.junit.runners.AndroidJUnit4;

import com.example.lottery.MainActivity;
import com.example.lottery.R;

import org.junit.Rule;
import org.junit.Test;
import org.junit.runner.RunWith;

import static androidx.test.espresso.Espresso.onView;
import static androidx.test.espresso.action.ViewActions.*;
import static androidx.test.espresso.assertion.ViewAssertions.matches;
import static androidx.test.espresso.matcher.ViewMatchers.*;

/**
 * Instrumented tests for US 03.09.01 - Admin multi-role capability.
 */
@RunWith(AndroidJUnit4.class)
public class AdminMultiRoleFragmentTest {

    @Rule
    public ActivityScenarioRule<MainActivity> activityRule =
            new ActivityScenarioRule<>(MainActivity.class);

    /**
     * US 03.09.01 - Test admin can access entrant features.
     */
    @Test
    public void adminCanAccessEntrantFeatures() {
        // Navigate to events tab (entrant feature)
        onView(withId(R.id.nav_events))
                .perform(click());

        onView(withId(R.id.recyclerView))
                .check(matches(isDisplayed()));
    }

    /**
     * US 03.09.01 - Test admin can access organizer features.
     */
    @Test
    public void adminCanAccessOrganizerFeatures() {
        // Navigate to organizer section
        onView(withId(R.id.nav_organizer))
                .perform(click());

        onView(withId(R.id.organizer_container))
                .check(matches(isDisplayed()));
    }

    /**
     * US 03.09.01 - Test admin panel button is visible.
     */
    @Test
    public void adminPanelButton_isDisplayed() {
        // Navigate to profile
        onView(withId(R.id.nav_profile))
                .perform(click());

        onView(withId(R.id.btnAdminPanel))
                .check(matches(isDisplayed()));
    }

    /**
     * US 03.09.01 - Test clicking admin panel opens admin features.
     */
    @Test
    public void adminPanelButton_opensAdminPanel() {
        // Navigate to profile
        onView(withId(R.id.nav_profile))
                .perform(click());

        onView(withId(R.id.btnAdminPanel))
                .perform(click());

        onView(withText("Admin Dashboard"))
                .check(matches(isDisplayed()));
    }

    /**
     * US 03.09.01 - Test admin can switch between roles.
     */
    @Test
    public void adminCanSwitchBetweenRoles() {
        // Access entrant features
        onView(withId(R.id.nav_events))
                .perform(click());

        onView(withId(R.id.recyclerView))
                .check(matches(isDisplayed()));

        // Access admin features
        onView(withId(R.id.nav_profile))
                .perform(click());

        onView(withId(R.id.btnAdminPanel))
                .perform(click());

        onView(withText("Admin Dashboard"))
                .check(matches(isDisplayed()));
    }
}

